define i8 @fold_add_umax_to_usub_multiuse(i8 %a) {
  %umax = call i8 @llvm.umax.i8(i8 %a, i8 10)
  call void @usei8(i8 %umax)
  %sel = add i8 %umax, -10
  ret i8 %sel
}

define i8 @sadd_sat_uge_int_max(i8 %x, i8 %y) {
  %cmp = icmp sge i8 %x, 127
  %add = add i8 %x, %y
  %r = select i1 %cmp, i8 127, i8 %add
  ret i8 %r
}
